// About.js
import React from 'react';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import useStyles from './styles';
import Soccer1 from '../../../images/soccer1.png';
import Soccer3 from '../../../images/soccer3.png';

const About = () => {
  const classes = useStyles();
  const isSmallScreen = useMediaQuery('(max-width:600px)');

  return (
    <Grid container spacing={3} className={classes.outerContainer}>
        {/* Höger sida */}
      <Grid item xs={12} sm={6}>
        {/* Textsektion */}
        <div className={isSmallScreen ? classes.textContainerAbout : classes.textContainer}>
          <Typography variant="h4" gutterBottom>
            About
          </Typography>
          <Typography variant="body1">
            Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna.
            Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam quis nostrud exercitation ullamco laboris nisi ut
          </Typography>
        </div>
      </Grid>
      
      {/* Vänster sida */}
      <Grid item xs={12} sm={6} className={isSmallScreen ? classes.imageContainer : classes.aboutGrid}>
        {/* Bild */}
        <div className={isSmallScreen ? classes.imageContainer : ''}>
          <img
            src={isSmallScreen ? Soccer1 : Soccer3}
            alt="Bild"
            className={isSmallScreen ? classes.imageAbout : classes.image}
          />
        </div>
      </Grid>
    </Grid>
  );
};

export default About;
